#nullable enable // autogenerated

using System.Collections.Generic;
using System.Linq;
using System.Xml;
using MVZ2.IO;
using MVZ2Logic;
using MVZ2Logic.Definitions;
using PVZEngine;

namespace MVZ2.Metas
{
    public class MapElementMeta
    {
        public string id;
        public XMLConditionList? unlockConditions;
        public Dictionary<string, object?> properties;
        public NamespaceID[] behaviours;

        private MapElementMeta(string id, Dictionary<string, object?> properties, NamespaceID[] behaviours)
        {
            this.id = id;
            this.properties = properties;
            this.behaviours = behaviours;
        }

        public static MapElementMeta? FromXmlNode(XmlNode node, string defaultNsp, IEnumerable<MapElementMetaTemplate> templates)
        {
            var id = node.GetAttribute("id");
            if (string.IsNullOrEmpty(id))
            {
                Log.LogError($"The {nameof(id)} of a {nameof(MapElementMeta)} is invalid.");
                return null;
            }
            XMLConditionList? unlockConditions = null;
            var unlockNode = node["unlock"];
            if (unlockNode != null)
            {
                unlockConditions = XMLConditionList.FromXmlNode(unlockNode, defaultNsp);
            }


            // 加载地图元素行为与属性。
            var templateID = node.GetAttribute("template");
            var template = templates.FirstOrDefault(t => t.id == templateID);

            var behaviours = new List<BehaviourItem>();
            Dictionary<string, object?> properties = new Dictionary<string, object?>();

            var behavioursNode = node["behaviours"];
            var propertyNode = node["properties"];
            propertyNode?.LoadPropertiesFromNode(defaultNsp, LogicPropertyRegions.mapElement, properties);
            if (template != null)
            {
                XMLHelper.LoadBehavioursAndPropertiesFromTemplate(defaultNsp, LogicDefinitionTypes.MAP_ELEMENT_BEHAVIOUR, template, behaviours, properties);
            }
            behavioursNode?.LoadBehavioursFromNode(defaultNsp, LogicDefinitionTypes.MAP_ELEMENT_BEHAVIOUR, behaviours, properties);

            var behavioursArray = behaviours.OrderBy(b => b.priority).Select(b => b.id).ToArray();

            return new MapElementMeta(id, properties, behavioursArray)
            {
                unlockConditions = unlockConditions
            };
        }
    }
}
